mapper.select:
select id, exam_id, student_id, answer_status, switch_count, create_time, update_time, deleted
from exam_student
where deleted = 0
  and exam_id = #{examId}
  and student_id = #{studentId}
limit 1

mapper.update:
update exam_student
set answer_status = #{answerStatus},
    update_time = case
        when #{answerStatus} = 'ANSWERING' then #{updateTime}
        else update_time
    end
where exam_id = #{examId}
  and student_id = #{studentId}
  and deleted = 0

update exam_student
set switch_count = case when switch_count > #{switchCount} then switch_count else #{switchCount} end
where exam_id = #{examId}
  and student_id = #{studentId}
  and answer_status = 'ANSWERING'
  and deleted = 0
